const EMOJI_META_MAP = new Map(EMOJI_META.map((entry) => [entry.emoji, entry]));
const EMOJI_CATEGORY_OVERRIDES = new Map([
  ['🕳', { category: 'smileys' }],
  ['🕳️', { category: 'smileys' }]
]);

function normalizeIconValue(value) {
  return typeof value === 'string' ? value.trim() : '';
}


function normalizeEmojiKey(value) {
  return normalizeIconValue(value).replace(/\uFE0F/g, '');
}

const SKIN_TONE_MODIFIERS = ['\u{1F3FB}','\u{1F3FC}','\u{1F3FD}','\u{1F3FE}','\u{1F3FF}'];
const SKIN_TONE_VALUES = ['default','1','2','3','4','5'];
const SKIN_TONE_REGEX = /[\u{1F3FB}-\u{1F3FF}]/gu;
const SKIN_TONE_OPTIONS = [
  { value: 'default', emoji: '🟡', label: 'Teinte par défaut' },
  { value: '1', emoji: '🏻', label: 'Clair' },
  { value: '2', emoji: '🏼', label: 'Moyen-clair' },
  { value: '3', emoji: '🏽', label: 'Moyen' },
  { value: '4', emoji: '🏾', label: 'Moyen-foncé' },
  { value: '5', emoji: '🏿', label: 'Foncé' },
];

function removeSkinTone(value) {
  return normalizeIconValue(value).replace(SKIN_TONE_REGEX, '');
}

function getSkinToneValue(value) {
  const clean = normalizeIconValue(value);
  for (let i = 0; i < SKIN_TONE_MODIFIERS.length; i++) {
    if (clean.includes(SKIN_TONE_MODIFIERS[i])) return String(i + 1);
  }
  return 'default';
}

function buildSkinToneCandidate(baseEmoji, toneValue) {
  if (toneValue === 'default') return normalizeIconValue(baseEmoji);
  const idx = Number(toneValue) - 1;
  const modifier = SKIN_TONE_MODIFIERS[idx];
  if (!modifier) return normalizeIconValue(baseEmoji);
  const source = normalizeIconValue(baseEmoji);
  if (!source) return source;
  return source.replace(/\uFE0F/g, '').replace(/\u200D/g, '\u200D').replace(/([\p{Extended_Pictographic}])(\u200D|$)/u, `$1${modifier}$2`);
}

function buildEmojiSkinIndex(entries) {
  const map = new Map();
  for (const entry of entries) {
    const baseKey = normalizeEmojiKey(removeSkinTone(entry.emoji));
    let bucket = map.get(baseKey);
    if (!bucket) {
      bucket = { baseKey, defaultEntry: null, tones: new Map(), all: [] };
      map.set(baseKey, bucket);
    }
    const tone = getSkinToneValue(entry.emoji);
    bucket.all.push(entry);
    if (tone === 'default') {
      bucket.defaultEntry = entry;
    } else {
      bucket.tones.set(tone, entry);
    }
  }
  for (const bucket of map.values()) {
    if (!bucket.defaultEntry) {
      bucket.defaultEntry = bucket.all.slice().sort((a, b) => a.order - b.order || a.name.localeCompare(b.name))[0] || null;
    }
  }
  return map;
}

function isLucideIcon(value) {
  return normalizeIconValue(value).toLowerCase().startsWith(LUCIDE_PREFIX);
}

function getLucideName(value) {
  return normalizeIconValue(value).slice(LUCIDE_PREFIX.length).trim();
}

function isExplorerRenameActive(root = document) {
  return !!root.querySelector(
    '.nav-file-title.is-being-renamed, .nav-folder-title.is-being-renamed, .tree-item-self.is-being-renamed, .nav-file-title-content[contenteditable="true"], .nav-folder-title-content[contenteditable="true"], input[type="text"].nav-file-title-content, input[type="text"].nav-folder-title-content'
  );
}

function scoreEmojiEntry(entry, query) {
  if (!query) return 0;
  const q = query.toLowerCase();
  if (entry.emoji === q) return 1000;
  if (entry.name === q) return 700;
  if (entry.name.startsWith(q)) return 500;
  if (entry.aliases.some((a) => a === q)) return 450;
  if (entry.aliases.some((a) => a.startsWith(q))) return 300;
  if (entry.keywords.some((k) => k === q)) return 240;
  if (entry.keywords.some((k) => k.startsWith(q))) return 180;
  if (entry.name.includes(q)) return 150;
  if (entry.aliases.some((a) => a.includes(q))) return 120;
  if (entry.keywords.some((k) => k.includes(q))) return 80;
  return -1;
}

function getEmojiMeta(entry) {
  const meta = EMOJI_META_MAP.get(entry.emoji) || EMOJI_META_MAP.get(normalizeEmojiKey(entry.emoji)) || { category: 'symbols', order: Number.MAX_SAFE_INTEGER };
  const override = EMOJI_CATEGORY_OVERRIDES.get(entry.emoji) || EMOJI_CATEGORY_OVERRIDES.get(normalizeEmojiKey(entry.emoji));
  return override ? { ...meta, ...override } : meta;
}

const EMOJI_DATA_ENRICHED = EMOJI_DATA.map((entry) => ({ ...entry, ...getEmojiMeta(entry) }));
const EMOJI_SKIN_INDEX = buildEmojiSkinIndex(EMOJI_DATA_ENRICHED);
const EMOJI_BASE_ENTRIES = Array.from(EMOJI_SKIN_INDEX.values())
  .map((bucket) => bucket.defaultEntry)
  .filter(Boolean)
  .sort((a, b) => a.order - b.order || a.name.localeCompare(b.name));
const EMOJI_BY_CATEGORY = new Map(
  EMOJI_CATEGORIES.map((c) => [
    c.id,
    EMOJI_BASE_ENTRIES.filter((e) => e.category === c.id).sort((a, b) => a.order - b.order)
  ])
);

class OfflineIconPickerModal extends Modal {
  constructor(app, currentValue, onPick) {
    super(app);
    this.currentValue = normalizeIconValue(currentValue);
    this.onPick = onPick;
    this._cleanupFns = [];
    this._emojiSearchCache = new Map();
    this.activeTab = isLucideIcon(this.currentValue) ? 'icons' : 'emoji';
    this.emojiCategory = 'smileys';
    this.selectedSkinTone = getSkinToneValue(this.currentValue);
    this.iconIds = Array.from(new Set((typeof getIconIds === 'function' ? getIconIds() : []).filter(Boolean)));
    if (!isLucideIcon(this.currentValue) && this.currentValue) {
      const currentEmoji = EMOJI_DATA_ENRICHED.find((entry) => entry.emoji === this.currentValue || normalizeEmojiKey(entry.emoji) === normalizeEmojiKey(this.currentValue));
      if (currentEmoji?.category) this.emojiCategory = currentEmoji.category;
    }
  }

  onOpen() {
    const { contentEl } = this;
    contentEl.empty();
    contentEl.addClass('npis-picker-modal');
    this.modalEl.addClass('npis-picker-modal-shell');

    contentEl.createEl('h3', { text: 'Choisir une icône', cls: 'npis-picker-title' });

    const tabs = contentEl.createDiv({ cls: 'npis-picker-tabs' });
    const emojiTab = tabs.createEl('button', { text: 'Emoji', cls: 'npis-picker-tab npis-picker-tab-text' });
    const iconTab = tabs.createEl('button', { text: 'Icônes', cls: 'npis-picker-tab npis-picker-tab-text' });
    emojiTab.title = 'Emojis';
    iconTab.title = 'Icônes';
    emojiTab.setAttribute('aria-label', 'Emojis');
    iconTab.setAttribute('aria-label', 'Icônes');
    emojiTab.type = 'button';
    iconTab.type = 'button';

    const body = contentEl.createDiv({ cls: 'npis-picker-body' });
    const emojiPane = body.createDiv({ cls: 'npis-picker-pane npis-picker-pane-emoji' });
    const iconPane = body.createDiv({ cls: 'npis-picker-pane npis-picker-pane-icons' });

    this.buildEmojiPane(emojiPane);
    this.buildIconPane(iconPane);

    const removeBtn = tabs.createEl('button', { text: 'Retirer', cls: 'npis-picker-remove-tab' });
    removeBtn.type = 'button';
    removeBtn.addEventListener('click', () => {
      this.onPick(null);
      this.close();
    });

    const setActiveTab = (tab) => {
      this.activeTab = tab;
      emojiTab.classList.toggle('is-active', tab === 'emoji');
      iconTab.classList.toggle('is-active', tab === 'icons');
      emojiPane.classList.toggle('is-active', tab === 'emoji');
      iconPane.classList.toggle('is-active', tab === 'icons');
      window.setTimeout(() => {
        if (tab === 'emoji') this.emojiSearchEl?.focus();
        else this.iconSearchEl?.focus();
      }, 0);
    };

    emojiTab.addEventListener('click', () => setActiveTab('emoji'));
    iconTab.addEventListener('click', () => setActiveTab('icons'));
    setActiveTab(this.activeTab);
  }


  buildEmojiPane(emojiPane) {
    const topbar = emojiPane.createDiv({ cls: 'npis-emoji-topbar' });
    const searchRow = topbar.createDiv({ cls: 'npis-emoji-search-row' });
    const search = searchRow.createEl('input', { type: 'search', cls: 'npis-picker-search npis-picker-search-with-clear' });
    search.placeholder = 'Rechercher un emoji';
    this.emojiSearchEl = search;

    const clearSearchBtn = searchRow.createEl('button', { cls: 'npis-search-clear-btn' });
    clearSearchBtn.type = 'button';
    clearSearchBtn.setAttribute('aria-label', 'Effacer la recherche');
    clearSearchBtn.title = 'Effacer';
    clearSearchBtn.setText('×');

    const skinToneBtn = searchRow.createEl('button', { cls: 'npis-skin-tone-trigger' });
    skinToneBtn.type = 'button';

    const info = emojiPane.createDiv({ cls: 'npis-results-meta' });
    const gridWrap = emojiPane.createDiv({ cls: 'npis-picker-scroll npis-emoji-scroll' });
    const grid = gridWrap.createDiv({ cls: 'npis-emoji-grid npis-emoji-grid-compact' });
    const categoryTabs = emojiPane.createDiv({ cls: 'npis-emoji-category-tabs' });

    let skinTonePopover = null;

    const updateSkinToneButton = () => {
      const selected = SKIN_TONE_OPTIONS.find((option) => option.value === this.selectedSkinTone) || SKIN_TONE_OPTIONS[0];
      skinToneBtn.empty();
      skinToneBtn.setAttribute('aria-label', 'Choisir la teinte de peau');
      skinToneBtn.title = selected.label;
      skinToneBtn.createSpan({ text: selected.emoji, cls: 'npis-skin-tone-trigger-emoji' });
    };

    const closeSkinTonePopover = () => {
      if (skinTonePopover) {
        skinTonePopover.remove();
        skinTonePopover = null;
      }
    };

    const openSkinTonePopover = () => {
      if (skinTonePopover) {
        closeSkinTonePopover();
        return;
      }
      skinTonePopover = searchRow.createDiv({ cls: 'npis-skin-tone-popover' });
      for (const option of SKIN_TONE_OPTIONS) {
        const btn = skinTonePopover.createEl('button', { cls: 'npis-skin-tone-option' });
        btn.type = 'button';
        btn.title = option.label;
        btn.setAttribute('aria-label', option.label);
        btn.setText(option.emoji);
        btn.classList.toggle('is-active', option.value === this.selectedSkinTone);
        btn.addEventListener('click', () => {
          this.selectedSkinTone = option.value;
          closeSkinTonePopover();
          updateSkinToneButton();
          render();
        });
      }
    };

    const clickAwayHandler = (evt) => {
      if (!skinTonePopover) return;
      if (skinTonePopover.contains(evt.target) || skinToneBtn.contains(evt.target)) return;
      closeSkinTonePopover();
    };

    document.addEventListener('click', clickAwayHandler, true);
    this._cleanupFns.push(() => document.removeEventListener('click', clickAwayHandler, true));
    updateSkinToneButton();

    skinToneBtn.addEventListener('click', (evt) => {
      evt.preventDefault();
      evt.stopPropagation();
      openSkinTonePopover();
    });

    const tabButtons = new Map();
    for (const category of EMOJI_CATEGORIES) {
      const btn = categoryTabs.createEl('button', { cls: 'npis-emoji-category-tab' });
      btn.type = 'button';
      btn.title = category.label;
      btn.setAttribute('aria-label', `Aller à la catégorie : ${category.label}`);
      btn.setAttribute('aria-pressed', 'false');
      const iconWrap = btn.createSpan({ cls: 'npis-emoji-category-tab-icon' });
      iconWrap.innerHTML = EMOJI_CATEGORY_SVGS[category.id] || '';
      btn.addEventListener('click', () => {
        this.emojiCategory = category.id;
        render();
      });
      tabButtons.set(category.id, btn);
    }

    const resolveEmojiForTone = (entry) => {
      const bucket = EMOJI_SKIN_INDEX.get(normalizeEmojiKey(removeSkinTone(entry.emoji)));
      if (!bucket) return entry.emoji;
      if (this.selectedSkinTone !== 'default' && bucket.tones.has(this.selectedSkinTone)) {
        return bucket.tones.get(this.selectedSkinTone).emoji;
      }
      return bucket.defaultEntry?.emoji || entry.emoji;
    };

    let currentResults = [];

    grid.addEventListener('click', (evt) => {
      const btn = evt.target.closest('.npis-emoji-btn');
      if (!btn) return;
      const idx = Number(btn.getAttribute('data-emoji-index'));
      const entry = currentResults[idx];
      if (!entry) return;
      this.onPick(resolveEmojiForTone(entry));
      this.close();
    });

    const render = () => {
      const query = String(search.value || '').trim().toLowerCase();
      grid.empty();
      for (const [id, btn] of tabButtons) {
        const active = id === this.emojiCategory;
        btn.classList.toggle('is-active', active);
        btn.setAttribute('aria-pressed', active ? 'true' : 'false');
      }

      let results;
      if (query) {
        if (!this._emojiSearchCache.has(query)) {
          const computed = EMOJI_BASE_ENTRIES
            .map((entry) => ({ entry, score: scoreEmojiEntry(entry, query) }))
            .filter((item) => item.score >= 0)
            .sort((a, b) => b.score - a.score || a.entry.order - b.entry.order || a.entry.name.localeCompare(b.entry.name))
            .slice(0, MAX_EMOJI_RESULTS)
            .map((item) => item.entry);
          this._emojiSearchCache.set(query, computed);
        }
        results = this._emojiSearchCache.get(query) || [];
        info.setText(results.length ? `${results.length} résultat${results.length > 1 ? 's' : ''}` : 'Aucun emoji trouvé');
      } else {
        const pool = EMOJI_BY_CATEGORY.get(this.emojiCategory) || EMOJI_BASE_ENTRIES;
        results = pool;
        const category = EMOJI_CATEGORIES.find((c) => c.id === this.emojiCategory);
        info.setText(category ? category.label : 'Emojis');
      }

      currentResults = results;

      if (!results.length) {
        grid.createDiv({ cls: 'npis-empty-state', text: 'Aucun emoji trouvé.' });
        return;
      }

      const frag = document.createDocumentFragment();
      for (let i = 0; i < results.length; i++) {
        const entry = results[i];
        const btn = document.createElement('button');
        btn.className = 'npis-emoji-btn npis-emoji-btn-compact';
        btn.type = 'button';
        btn.setAttribute('aria-label', entry.name);
        btn.title = entry.name;
        btn.setAttribute('data-emoji-index', String(i));
        btn.textContent = resolveEmojiForTone(entry);
        frag.appendChild(btn);
      }
      grid.appendChild(frag);
    };

    const updateClearButton = () => {
      const hasValue = !!String(search.value || '').length;
      clearSearchBtn.classList.toggle('is-visible', hasValue);
      clearSearchBtn.disabled = !hasValue;
    };

    clearSearchBtn.addEventListener('click', () => {
      search.value = '';
      updateClearButton();
      render();
      search.focus();
    });

    search.addEventListener('input', () => {
      updateClearButton();
      render();
    });
    updateClearButton();
    render();
  }

  buildIconPane(iconPane) {
    iconPane.addClass('npis-picker-pane-icons');

    const searchRow = iconPane.createDiv({ cls: 'npis-icon-search-row npis-icon-search-row-with-clear' });
    const search = searchRow.createEl('input', { type: 'search', cls: 'npis-picker-search npis-picker-search-with-clear' });
    search.placeholder = 'Rechercher une icône Lucide';
    if (isLucideIcon(this.currentValue)) search.value = getLucideName(this.currentValue);
    this.iconSearchEl = search;

    const clearSearchBtn = searchRow.createEl('button', { cls: 'npis-search-clear-btn npis-icon-search-clear-btn' });
    clearSearchBtn.type = 'button';
    clearSearchBtn.setAttribute('aria-label', 'Effacer la recherche');
    clearSearchBtn.title = 'Effacer';
    clearSearchBtn.setText('×');

    const info = iconPane.createDiv({ cls: 'npis-results-meta' });
    const gridWrap = iconPane.createDiv({ cls: 'npis-picker-scroll npis-icon-scroll' });
    const grid = gridWrap.createDiv({ cls: 'npis-icon-grid npis-icon-grid-compact' });

    const render = () => {
      const query = String(search.value || '').trim().toLowerCase();
      grid.empty();

      const filtered = query
        ? this.iconIds
            .map((name, index) => ({ name, index, lower: name.toLowerCase() }))
            .filter((item) => item.lower.includes(query))
            .sort((a, b) => {
              const as = a.lower.startsWith(query);
              const bs = b.lower.startsWith(query);
              if (as !== bs) return as ? -1 : 1;
              return a.index - b.index;
            })
            .map((item) => item.name)
        : this.iconIds;

      const visible = filtered.slice(0, MAX_ICON_RESULTS);
      info.setText(
        filtered.length > visible.length
          ? `${filtered.length} résultats. Affichage des ${visible.length} premiers.`
          : `${filtered.length} résultat${filtered.length > 1 ? 's' : ''}`
      );

      if (!visible.length) {
        grid.createDiv({ text: 'Aucune icône trouvée.', cls: 'npis-empty-state' });
        return;
      }

      for (const name of visible) {
        const btn = grid.createEl('button', { cls: 'npis-icon-btn npis-icon-btn-compact' });
        btn.type = 'button';
        btn.title = name;
        btn.setAttribute('aria-label', name);
        const iconBox = btn.createDiv({ cls: 'npis-icon-btn-preview' });
        setIcon(iconBox, name);
        iconBox.querySelectorAll('svg, .svg-icon').forEach((node) => { node.style.pointerEvents = 'none'; });
        btn.addEventListener('click', () => {
          this.onPick(`${LUCIDE_PREFIX}${name}`);
          this.close();
        });
      }
    };

    const updateClearButton = () => {
      const hasValue = !!String(search.value || '').length;
      clearSearchBtn.classList.toggle('is-visible', hasValue);
      clearSearchBtn.disabled = !hasValue;
    };

    clearSearchBtn.addEventListener('click', () => {
      search.value = '';
      updateClearButton();
      render();
      search.focus();
    });

    search.addEventListener('input', () => {
      updateClearButton();
      render();
    });
    updateClearButton();
    render();
  }

  onClose() {
    if (Array.isArray(this._cleanupFns)) {
      for (const fn of this._cleanupFns.splice(0)) {
        try { fn(); } catch {}
      }
    }
    this.contentEl.empty();
  }
}

module.exports = class NotionPageIconsSyncPlugin extends Plugin {
  async onload() {
    this.settings = Object.assign({}, DEFAULT_SETTINGS, await this.loadData());
    this.observers = new Set();
    this.fileIconCache = new Map();
    this.folderIconCache = new Map();
    this.renamedFileIconCache = new Map();
    this._isRefreshingExplorer = false;
    this._suspendExplorerObserverUntil = 0;
    this._startupRefreshTimers = new Set();
    this._layoutRefreshTimers = new Set();

    this.refreshCaches();

    this.registerEvent(this.app.metadataCache.on('changed', () => {
      this.refreshCaches();
      this.scheduleRefresh();
    }));
    this.registerEvent(this.app.vault.on('rename', (file, oldPath) => {
      this.handleVaultRename(file, oldPath);
      this.refreshCaches();
      this.scheduleRefresh();
    }));
    this.registerEvent(this.app.vault.on('create', () => {
      this.refreshCaches();
      this.scheduleRefresh();
    }));
    this.registerEvent(this.app.workspace.on('file-open', () => this.decorateActiveTitle()));
    this.registerEvent(this.app.workspace.on('layout-change', () => {
      this.scheduleRefresh();
      this.queueLayoutRefreshes([0, 120, 260, 520]);
    }));
    this.registerDomEvent(window, 'resize', () => this.queueLayoutRefreshes([0, 120, 260, 520]));
    this.registerDomEvent(document, 'transitionend', (evt) => {
      const target = evt?.target;
      if (!(target instanceof HTMLElement)) return;
      if (!target.closest('.workspace-split, .workspace-leaf, .workspace-tabs, .mod-left-split, .mod-right-split, .workspace-sidedock-vault-profile')) return;
      this.queueLayoutRefreshes([0, 90, 220]);
    });

    this.registerMarkdownPostProcessor((el, ctx) => {
      if (!this.settings.showIconsInWikilinks) return;
      const sourcePath = typeof ctx?.sourcePath === 'string' ? ctx.sourcePath : '';
      if (this.shouldInjectWikilinkIcons(el, sourcePath)) this.decorateInternalLinks(el, sourcePath);
      else this.cleanupInternalLinkIcons(el);
    });

    this.queueBootstrapRefreshes([0, 120, 360]);

    this.app.workspace.onLayoutReady(() => {
      this.attachExplorerObserver();
      this.queueBootstrapRefreshes([0, 120, 360, 900, 1800]);
    });

    this.addCommand({
      id: 'refresh-notion-page-icons-sync',
      name: 'Refresh icons now',
      callback: () => {
        this.refreshCaches();
        this.refreshAll();
        window.setTimeout(() => this.refreshAll(), 120);
      }
    });
  }

  onunload() {
    this.clearBootstrapRefreshTimers();
    this.clearLayoutRefreshTimers();
    for (const obs of this.observers) obs.disconnect();
    this.observers.clear();
    document.querySelectorAll('.npis-inline-icon,.npis-folder-toggle-icon,.npis-title-icon,.npis-link-icon,.npis-inline-title-icon-slot').forEach((el) => el.remove());
    document.querySelectorAll('.npis-title-enhanced').forEach((el) => el.classList.remove('npis-title-enhanced'));
    document.querySelectorAll('.npis-inline-title-enhanced').forEach((el) => el.classList.remove('npis-inline-title-enhanced'));
    document.querySelectorAll('.npis-inline-title-parent[data-npis-title-wrapper="1"]').forEach((wrapper) => {
      const parent = wrapper.parentElement;
      if (!parent) return;
      const titleEl = wrapper.querySelector(':scope > .inline-title');
      if (titleEl) parent.insertBefore(titleEl, wrapper);
      wrapper.remove();
    });
  }

  async saveSettings() {
    await this.saveData(this.settings);
  }

  scheduleRefresh() {
    if (this._isRefreshingExplorer) return;
    window.clearTimeout(this._refreshTimer);
    this._refreshTimer = window.setTimeout(() => this.refreshAll(), 60);
  }

  clearBootstrapRefreshTimers() {
    if (!this._startupRefreshTimers) return;
    for (const timer of this._startupRefreshTimers) {
      window.clearTimeout(timer);
    }
    this._startupRefreshTimers.clear();
  }

  clearLayoutRefreshTimers() {
    if (!this._layoutRefreshTimers) return;
    for (const timer of this._layoutRefreshTimers) {
      window.clearTimeout(timer);
    }
    this._layoutRefreshTimers.clear();
  }

  queueBootstrapRefreshes(delays = [0, 120, 360, 900]) {
    this.clearBootstrapRefreshTimers();
    for (const delay of delays) {
      const timer = window.setTimeout(() => {
        this._startupRefreshTimers?.delete(timer);
        this.refreshCaches();
        this.attachExplorerObserver();
        this.refreshAll();
      }, delay);
      this._startupRefreshTimers.add(timer);
    }
  }

  queueLayoutRefreshes(delays = [0, 120, 260, 520]) {
    for (const delay of delays) {
      const timer = window.setTimeout(() => {
        this._layoutRefreshTimers?.delete(timer);
        this.refreshAll();
      }, delay);
      this._layoutRefreshTimers?.add(timer);
    }
  }

  refreshCaches() {
    this.fileIconCache.clear();
    this.folderIconCache.clear();

    const markdownFiles = this.app.vault.getMarkdownFiles();

    for (const file of markdownFiles) {
      const icon = this.extractIconFromFile(file);
      if (!icon) continue;
      this.fileIconCache.set(file.path, icon);

      const cache = this.app.metadataCache.getFileCache(file);
      const fm = cache?.frontmatter;
      const parent = file.parent;
      if (parent && file.basename === parent.name) {
        this.folderIconCache.set(parent.path, icon);
      }

      if (fm?.foldernote === true && parent) {
        this.folderIconCache.set(parent.path, icon);
      }
    }

    for (const [path, icon] of Array.from(this.renamedFileIconCache.entries())) {
      const file = this.app.vault.getAbstractFileByPath(path);
      if (!file || !file.path) {
        this.renamedFileIconCache.delete(path);
        continue;
      }
      const confirmed = this.fileIconCache.get(path);
      if (confirmed === icon || !!confirmed) this.renamedFileIconCache.delete(path);
    }
  }

  extractIconFromFile(file) {
    if (!file) return '';
    const cache = this.app.metadataCache.getFileCache(file);
    const fm = cache?.frontmatter;
    const icon = typeof fm?.[this.settings.iconField] === 'string' ? fm[this.settings.iconField].trim() : '';
    return icon || '';
  }

  lookupIconFromPath(path) {
    if (!path) return '';
    const file = this.app.vault.getAbstractFileByPath(path);
    return this.extractIconFromFile(file);
  }

  getFileFromPath(path) {
    if (!path || typeof path !== 'string') return null;
    const file = this.app.vault.getAbstractFileByPath(path);
    return file?.path ? file : null;
  }

  normalizeCssClassList(value) {
    if (Array.isArray(value)) {
      return value
        .flatMap((entry) => this.normalizeCssClassList(entry))
        .filter(Boolean);
    }

    if (typeof value !== 'string') return [];

    return value
      .split(/[\s,]+/)
      .map((entry) => entry.trim().toLowerCase())
      .filter(Boolean);
  }

  getCssClassesForFile(fileOrPath) {
    const file = typeof fileOrPath === 'string' ? this.getFileFromPath(fileOrPath) : fileOrPath;
    if (!file) return [];

    const cache = this.app.metadataCache.getFileCache(file);
    const fm = cache?.frontmatter;
    const raw = fm?.cssclasses ?? fm?.cssclass;
    return this.normalizeCssClassList(raw);
  }

  fileHasCssClass(fileOrPath, className) {
    if (!className || typeof className !== 'string') return false;
    const wanted = className.trim().toLowerCase();
    if (!wanted) return false;
    return this.getCssClassesForFile(fileOrPath).includes(wanted);
  }

  cleanupInternalLinkIcons(root) {
    if (!root || !(root instanceof HTMLElement)) return;
    root.querySelectorAll('.npis-link-icon').forEach((el) => el.remove());
  }

  rootHasCssClassContext(root, className) {
    if (!root || !(root instanceof HTMLElement) || !className || typeof className !== 'string') return false;
    const wanted = className.trim().toLowerCase();
    if (!wanted) return false;

    let node = root;
    while (node instanceof HTMLElement) {
      const classes = Array.from(node.classList || []).map((entry) => String(entry).trim().toLowerCase()).filter(Boolean);
      if (classes.includes(wanted)) return true;
      node = node.parentElement;
    }

    return false;
  }

  shouldInjectWikilinkIcons(root, sourcePath = '') {
    return this.rootHasCssClassContext(root, 'notion-list') || this.fileHasCssClass(sourcePath, 'notion-list');
  }

  refreshWikilinkIcons() {
    const leaves = this.app.workspace.getLeavesOfType('markdown');
    for (const leaf of leaves) {
      const view = leaf.view;
      if (!(view instanceof MarkdownView)) continue;
      const containerEl = view.containerEl;
      if (!(containerEl instanceof HTMLElement)) continue;

      const sourcePath = view.file?.path || '';
      const roots = new Set([containerEl]);
      containerEl.querySelectorAll('.markdown-rendered, .markdown-preview-view, .markdown-source-view, .cm-contentContainer, .cm-content, .cm-line').forEach((el) => {
        if (el instanceof HTMLElement) roots.add(el);
      });

      for (const root of roots) {
        if (this.shouldInjectWikilinkIcons(root, sourcePath)) this.decorateInternalLinks(root, sourcePath);
        else this.cleanupInternalLinkIcons(root);
      }
    }

    document.querySelectorAll('.npis-link-icon').forEach((el) => {
      if (!(el instanceof HTMLElement)) return;
      if (!el.closest('.notion-list')) el.remove();
    });
  }

  handleVaultRename(file, oldPath) {
    if (!file?.path || !oldPath || oldPath === file.path) return;
    const carriedIcon = this.fileIconCache.get(oldPath) || this.renamedFileIconCache.get(oldPath) || this.lookupIconFromPath(oldPath);
    if (carriedIcon) this.renamedFileIconCache.set(file.path, carriedIcon);
    else this.renamedFileIconCache.delete(file.path);
    this.renamedFileIconCache.delete(oldPath);
  }

  refreshAll() {
    if (this.settings.showIconsInExplorer) {
      this._isRefreshingExplorer = true;
      this._suspendExplorerObserverUntil = Date.now() + 150;
      try {
        this.decorateFileExplorer();
      } finally {
        window.setTimeout(() => {
          this._isRefreshingExplorer = false;
        }, 0);
      }
    }
    if (this.settings.showIconsInTitle) {
      this.decorateActiveTitle();
      this.decorateInlineTitles();
    }
    if (this.settings.showIconsInWikilinks) this.refreshWikilinkIcons();
  }

  attachExplorerObserver() {
    const explorerLeaves = this.app.workspace.getLeavesOfType('file-explorer');
    for (const leaf of explorerLeaves) {
      const root = leaf.view?.containerEl;
      if (!root) continue;
      if (!root._npisObserverAttached) {
        const obs = new MutationObserver((mutations) => {
          if (this._isRefreshingExplorer) return;
          if (Date.now() < (this._suspendExplorerObserverUntil || 0)) return;
          if (isExplorerRenameActive(root)) return;

          const hasRelevantMutation = mutations.some((mutation) => {
            if (mutation.type !== 'childList') return false;
            const changedNodes = [...mutation.addedNodes, ...mutation.removedNodes];
            return changedNodes.some((node) => {
              if (!(node instanceof HTMLElement)) return true;
              if (node.classList.contains('npis-inline-icon')) return false;
              if (node.classList.contains('npis-folder-toggle-icon')) return false;
              if (node.classList.contains('npis-title-icon')) return false;
              if (node.classList.contains('npis-link-icon')) return false;
              if (node.classList.contains('npis-inline-title-icon-slot')) return false;
              if (node.querySelector?.('.npis-inline-icon, .npis-folder-toggle-icon, .npis-title-icon, .npis-link-icon, .npis-inline-title-icon-slot')) return false;
              return true;
            });
          });

          if (!hasRelevantMutation) return;
          this.scheduleRefresh();
        });
        obs.observe(root, { childList: true, subtree: true });
        root._npisObserverAttached = true;
        this.observers.add(obs);
      }
      this.attachExplorerResizeObserver(root);
    }
  }

  attachExplorerResizeObserver(root) {
    if (!root || root._npisResizeObserverAttached || typeof ResizeObserver === 'undefined') return;
    let lastWidth = Math.round(root.getBoundingClientRect().width || 0);
    let lastHeight = Math.round(root.getBoundingClientRect().height || 0);
    const obs = new ResizeObserver((entries) => {
      const entry = entries?.[0];
      const rect = entry?.contentRect;
      const nextWidth = Math.round(rect?.width || root.getBoundingClientRect().width || 0);
      const nextHeight = Math.round(rect?.height || root.getBoundingClientRect().height || 0);
      if (nextWidth === lastWidth && nextHeight === lastHeight) return;
      lastWidth = nextWidth;
      lastHeight = nextHeight;
      this.queueLayoutRefreshes([0, 90, 220, 420]);
    });
    obs.observe(root);
    root._npisResizeObserverAttached = true;
    this.observers.add(obs);
  }

  getIconForFilePath(path) {
    return this.fileIconCache.get(path)
      || this.renamedFileIconCache.get(path)
      || this.lookupIconFromPath(path)
      || this.getFallbackIconForFilePath(path)
      || '';
  }

  getIconForFolderPath(path) {
    return this.folderIconCache.get(path) || '';
  }

  isBaseFilePath(path) {
    return typeof path === 'string' && /\.base$/i.test(path);
  }

  getFileExtension(path) {
    if (typeof path !== 'string' || !path) return '';
    const parts = path.split('.');
    if (parts.length < 2) return '';
    return parts.pop()?.toLowerCase() || '';
  }

  getFallbackIconByExtension(ext) {
    if (!ext) return '';

    const extensionGroups = {
      image: {
        icon: 'lucide:file-image',
        extensions: [
          'png', 'jpg', 'jpeg', 'gif', 'webp', 'svg', 'bmp', 'ico', 'avif', 'apng', 'tif', 'tiff', 'heic', 'heif'
        ]
      },
      book: {
        icon: 'lucide:book-open-text',
        extensions: ['pdf', 'epub']
      }
    };

    for (const group of Object.values(extensionGroups)) {
      if (group.extensions.includes(ext)) return group.icon;
    }

    return '';
  }

  getFallbackIconForFilePath(path) {
    if (typeof path !== 'string' || !path || this.isBaseFilePath(path)) return '';
    const ext = this.getFileExtension(path);
    return this.getFallbackIconByExtension(ext);
  }

  updateSpecialFallbackClass(el, path, icon) {
    if (!el) return;
    const hasExplicitIcon = typeof icon === 'string' && icon.trim().length > 0;
    const isBase = this.isBaseFilePath(path);
    const nextKind = !hasExplicitIcon && isBase ? 'base' : '';
    const prevKind = el.getAttribute('data-npis-fallback-kind') || '';
    if (nextKind) {
      el.setAttribute('data-npis-fallback-kind', nextKind);
    } else {
      el.removeAttribute('data-npis-fallback-kind');
    }
    if (prevKind !== nextKind) el.removeAttribute('data-npis-render-key');
  }

  createIconSpan(icon, extraClass = '') {
    const span = document.createElement('span');
    span.className = `npis-inline-icon ${extraClass}`.trim();
    span.setAttribute('aria-hidden', 'true');
    return span;
  }

  renderEmojiIcon(el, emoji) {
    const svgNS = 'http://www.w3.org/2000/svg';
    const svg = document.createElementNS(svgNS, 'svg');
    svg.setAttribute('viewBox', '0 0 100 100');
    svg.setAttribute('width', '100%');
    svg.setAttribute('height', '100%');
    svg.setAttribute('focusable', 'false');
    svg.setAttribute('aria-hidden', 'true');
    svg.style.pointerEvents = 'none';

    const text = document.createElementNS(svgNS, 'text');
    text.setAttribute('x', '50');
    text.setAttribute('y', '72');
    text.setAttribute('text-anchor', 'middle');
    text.setAttribute('font-size', '78');
    text.textContent = emoji;

    svg.appendChild(text);
    el.appendChild(svg);
  }

  setIconContent(el, icon) {
    const v = normalizeIconValue(icon);
    const fallbackKind = el.getAttribute('data-npis-fallback-kind') || '';
    const renderKey = `${v}::${fallbackKind}`;

    if (el.getAttribute('data-npis-render-key') === renderKey) return;
    el.setAttribute('data-npis-render-key', renderKey);

    if (typeof el.empty === 'function') el.empty();
    else el.innerHTML = '';
    el.textContent = '';

    const renderLucide = (name, isFallback = false) => {
      if (!name) return false;
      el.classList.remove('npis-fallback-mask', 'npis-icon-emoji');
      el.classList.add('npis-icon-lucide');
      if (isFallback) el.setAttribute('data-npis-fallback', '1');
      else el.removeAttribute('data-npis-fallback');
      setIcon(el, name);
      el.querySelectorAll('svg, .svg-icon').forEach((node) => { node.style.pointerEvents = 'none'; });
      return true;
    };

    if (isLucideIcon(v)) {
      const name = getLucideName(v);
      if (renderLucide(name, false)) return;
    }

    el.classList.remove('npis-icon-lucide');
    if (v) {
      el.classList.add('npis-icon-emoji');
      el.classList.remove('npis-fallback-mask');
      el.removeAttribute('data-npis-fallback');
      this.renderEmojiIcon(el, v);
    } else {
      el.classList.remove('npis-icon-emoji');
      el.textContent = '';
      const fallbackName = fallbackKind === 'base' ? 'grid-3x-2' : 'file-text';
      if (!renderLucide(fallbackName, true)) {
        el.classList.add('npis-fallback-mask');
        el.setAttribute('data-npis-fallback', '1');
      }
    }
  }

  decorateFileExplorer() {
    this.attachExplorerObserver();

    const explorerRoots = document.querySelectorAll('.workspace-leaf-content[data-type="file-explorer"]');
    explorerRoots.forEach((root) => {
      this.cleanupExplorerRenameArtifacts(root);
      if (isExplorerRenameActive(root)) return;

      root.querySelectorAll('.nav-file').forEach((fileEl) => {
        if (fileEl.querySelector('.is-being-renamed,[contenteditable="true"]')) return;
        const titleEl = fileEl.querySelector('.nav-file-title');
        const contentEl = fileEl.querySelector('.nav-file-title-content');
        if (!titleEl || !contentEl) return;
        const path = titleEl.getAttribute('data-path') || fileEl.getAttribute('data-path');
        if (!path) return;
        const icon = this.getIconForFilePath(path);
        this.ensureLeadingIcon(contentEl, icon, path);
      });

      root.querySelectorAll('.nav-folder').forEach((folderEl) => {
        if (folderEl.querySelector('.is-being-renamed,[contenteditable="true"]')) return;
        const titleEl = folderEl.querySelector('.nav-folder-title');
        const contentEl = folderEl.querySelector('.nav-folder-title-content');
        if (!titleEl || !contentEl) return;
        const folderPath = titleEl.getAttribute('data-path') || folderEl.getAttribute('data-path') || '';
        const icon = this.getIconForFolderPath(folderPath);
        if (this.settings.replaceFolderChevron) {
          this.removeLeadingIcon(contentEl);
          this.decorateFolderChevron(titleEl, icon);
        } else {
          this.ensureLeadingIcon(contentEl, icon, folderPath);
        }
      });
    });
  }

  ensureLeadingIcon(contentEl, icon, path = '') {
    let existing = contentEl.querySelector(':scope > .npis-inline-icon');
    if (!existing) {
      existing = this.createIconSpan(icon);
      contentEl.insertBefore(existing, contentEl.firstChild);
    }
    this.updateSpecialFallbackClass(existing, path, icon);
    this.setIconContent(existing, icon);
  }

  removeLeadingIcon(contentEl) {
    const existing = contentEl.querySelector(':scope > .npis-inline-icon');
    if (existing) existing.remove();
  }

  cleanupExplorerRenameArtifacts(root) {
    if (!root) return;
    const renameTargets = root.querySelectorAll(
      '.nav-file-title.is-being-renamed .nav-file-title-content, .nav-folder-title.is-being-renamed .nav-folder-title-content, .tree-item-self.is-being-renamed .nav-file-title-content, .tree-item-self.is-being-renamed .nav-folder-title-content, .nav-file-title-content[contenteditable="true"], .nav-folder-title-content[contenteditable="true"], input[type="text"].nav-file-title-content, input[type="text"].nav-folder-title-content'
    );
    renameTargets.forEach((contentEl) => {
      if (contentEl instanceof HTMLElement) this.removeLeadingIcon(contentEl);
    });
  }

  normalizeInlineTitleWrappers(containerEl) {
    if (!containerEl) return;

    containerEl.querySelectorAll('.npis-inline-title-parent[data-npis-title-wrapper="1"]').forEach((wrapper) => {
      if (!(wrapper instanceof HTMLElement)) return;
      const titleEls = wrapper.querySelectorAll(':scope > .inline-title');
      const iconEls = wrapper.querySelectorAll(':scope > .npis-inline-title-icon-slot');

      if (titleEls.length !== 1) {
        const parent = wrapper.parentElement;
        if (!parent) return;
        titleEls.forEach((titleEl) => parent.insertBefore(titleEl, wrapper));
        wrapper.remove();
        return;
      }

      iconEls.forEach((iconEl, index) => {
        if (index > 0) iconEl.remove();
      });
    });

    containerEl.querySelectorAll('.inline-title').forEach((titleEl) => {
      if (!(titleEl instanceof HTMLElement)) return;
      titleEl.querySelectorAll(':scope > .npis-inline-title-icon-slot').forEach((n) => n.remove());
    });
  }

  ensureInlineTitleWrapper(titleEl) {
    const currentParent = titleEl.parentElement;
    if (!currentParent) return null;

    const isDedicatedWrapper = currentParent.classList.contains('npis-inline-title-parent')
      && currentParent.dataset.npisTitleWrapper === '1';

    if (isDedicatedWrapper) {
      Array.from(currentParent.children).forEach((child) => {
        if (child !== titleEl && !child.classList?.contains('npis-inline-title-icon-slot')) child.remove();
      });
      currentParent.querySelectorAll(':scope > .npis-inline-title-icon-slot').forEach((child, index) => {
        if (index > 0) child.remove();
      });
      return currentParent;
    }

    const previousWrapper = titleEl.previousElementSibling;
    if (previousWrapper instanceof HTMLElement
      && previousWrapper.classList.contains('npis-inline-title-parent')
      && previousWrapper.dataset.npisTitleWrapper === '1'
      && !previousWrapper.querySelector('.inline-title')) {
      previousWrapper.remove();
    }

    const wrapper = document.createElement('div');
    wrapper.className = 'npis-inline-title-parent';
    wrapper.dataset.npisTitleWrapper = '1';
    currentParent.insertBefore(wrapper, titleEl);
    wrapper.appendChild(titleEl);
    return wrapper;
  }

  decorateInlineTitles() {
    const leaves = this.app.workspace.getLeavesOfType('markdown');
    for (const leaf of leaves) {
      const view = leaf.view;
      if (!(view instanceof MarkdownView)) continue;
      const file = view.file;
      if (!file) continue;
      const icon = this.getIconForFilePath(file.path);

      this.normalizeInlineTitleWrappers(view.containerEl);
      const titles = view.containerEl.querySelectorAll('.inline-title');
      titles.forEach((titleEl) => {
        if (!(titleEl instanceof HTMLElement) || !titleEl.isConnected) return;

        const wrapper = this.ensureInlineTitleWrapper(titleEl);
        if (!wrapper) return;

        let iconEl = wrapper.querySelector(':scope > .npis-inline-title-icon-slot');
        if (!iconEl) {
          iconEl = this.createIconSpan(icon, 'npis-inline-title-icon npis-inline-title-icon-slot');
          iconEl.setAttribute('contenteditable', 'false');
          wrapper.insertBefore(iconEl, titleEl);
        }
        this.updateSpecialFallbackClass(iconEl, file.path, icon);
        this.setIconContent(iconEl, icon);

        try {
          const titleIconSize = '60px';
          iconEl.style.fontSize = titleIconSize;
          iconEl.style.width = titleIconSize;
          iconEl.style.minWidth = titleIconSize;
          iconEl.style.maxWidth = titleIconSize;
          iconEl.style.height = titleIconSize;
          iconEl.style.minHeight = titleIconSize;
          iconEl.style.maxHeight = titleIconSize;
          iconEl.style.lineHeight = '1';
          iconEl.style.alignSelf = 'center';
        } catch {}

        this.attachIconPickerClick(iconEl, file);
        titleEl.classList.add('npis-inline-title-enhanced');
        wrapper.classList.add('npis-inline-title-parent');
      });
    }
  }

  decorateFolderChevron(folderTitleEl, icon) {
    const indicator = folderTitleEl.querySelector('.nav-folder-collapse-indicator, .tree-item-icon.collapse-icon');
    if (!indicator) return;

    folderTitleEl.classList.add('npis-folder-title-has-custom-toggle');

    let custom = folderTitleEl.querySelector(':scope > .npis-folder-toggle-icon');
    if (!custom) {
      custom = this.createIconSpan(icon, 'npis-folder-toggle-icon');
      custom.setAttribute('aria-hidden', 'true');
      folderTitleEl.appendChild(custom);
    }

    this.setIconContent(custom, icon);

    try {
      const indicatorRect = indicator.getBoundingClientRect();
      const titleRect = folderTitleEl.getBoundingClientRect();
      const titleStyle = window.getComputedStyle(folderTitleEl);
      const baseFontSize = parseFloat(titleStyle.fontSize || '16') || 16;
      const targetSize = baseFontSize * 1.2;

      const geometryIsStable = Number.isFinite(indicatorRect.left)
        && Number.isFinite(indicatorRect.top)
        && Number.isFinite(titleRect.left)
        && Number.isFinite(titleRect.top)
        && indicatorRect.width >= 8
        && indicatorRect.height >= 8
        && titleRect.width >= 24
        && titleRect.height >= 16;

      if (!geometryIsStable) {
        custom.style.visibility = custom.hasAttribute('data-npis-position-key') ? 'visible' : 'hidden';
        return;
      }

      const centeredLeft = (indicatorRect.left - titleRect.left) + ((indicatorRect.width - targetSize) / 2);
      const centeredTop = (indicatorRect.top - titleRect.top) + ((indicatorRect.height - targetSize) / 2);

      if (!Number.isFinite(centeredLeft) || !Number.isFinite(centeredTop)) {
        custom.style.visibility = custom.hasAttribute('data-npis-position-key') ? 'visible' : 'hidden';
        return;
      }

      const positionKey = `${Math.round(centeredLeft * 100) / 100}|${Math.round(centeredTop * 100) / 100}|${Math.round(targetSize * 100) / 100}|${Math.round(baseFontSize * 100) / 100}`;

      if (custom.getAttribute('data-npis-position-key') !== positionKey) {
        custom.style.left = `${centeredLeft}px`;
        custom.style.top = `${centeredTop}px`;
        custom.style.width = `${targetSize}px`;
        custom.style.minWidth = `${targetSize}px`;
        custom.style.maxWidth = `${targetSize}px`;
        custom.style.height = `${targetSize}px`;
        custom.style.minHeight = `${targetSize}px`;
        custom.style.maxHeight = `${targetSize}px`;
        custom.style.fontSize = `${baseFontSize}px`;
        custom.style.lineHeight = '1';
        custom.setAttribute('data-npis-position-key', positionKey);
      }

      custom.style.visibility = 'visible';
    } catch {
      custom.style.visibility = custom.hasAttribute('data-npis-position-key') ? 'visible' : 'hidden';
    }
  }

  decorateActiveTitle() {
    if (!this.settings.showIconsInTitle) return;

    const leaves = this.app.workspace.getLeavesOfType('markdown');
    for (const leaf of leaves) {
      const view = leaf.view;
      if (!(view instanceof MarkdownView)) continue;
      const file = view.file;
      if (!file) continue;

      const titleContainer = view.containerEl.querySelector('.view-header-title-container');
      const titleEl = view.containerEl.querySelector('.view-header-title');
      if (!titleContainer || !titleEl) continue;

      const dup = titleContainer.querySelectorAll(':scope > .npis-title-icon');
      dup.forEach((n, i) => {
        if (i > 0) n.remove();
      });
      let iconEl = titleContainer.querySelector(':scope > .npis-title-icon');
      const icon = this.getIconForFilePath(file.path);

      if (!iconEl) {
        iconEl = this.createIconSpan(icon, 'npis-title-icon');
        titleContainer.insertBefore(iconEl, titleContainer.firstChild);
      }
      this.updateSpecialFallbackClass(iconEl, file.path, icon);
      this.setIconContent(iconEl, icon);
      try {
        const cs = window.getComputedStyle(titleEl);
        iconEl.style.fontSize = cs.fontSize;
        iconEl.style.width = cs.fontSize;
        iconEl.style.minWidth = cs.fontSize;
        iconEl.style.height = cs.fontSize;
        iconEl.style.lineHeight = '1';
        iconEl.style.alignSelf = 'center';
      } catch {}
      this.attachIconPickerClick(iconEl, file);
      titleContainer.classList.add('npis-title-enhanced');
    }
  }

  decorateInternalLinks(root, sourcePath = '') {
    if (!root || !(root instanceof HTMLElement)) return;
    if (!this.shouldInjectWikilinkIcons(root, sourcePath)) {
      this.cleanupInternalLinkIcons(root);
      return;
    }

    const links = root.querySelectorAll('a.internal-link');
    links.forEach((link) => {
      if (link.closest('.view-header,.inline-title,.metadata-container,.cm-header')) return;
      link.querySelectorAll(':scope > .npis-link-icon').forEach((n, i) => {
        if (i > 0) n.remove();
      });

      let iconSpan = link.querySelector(':scope > .npis-link-icon');

      const rawCandidates = [
        link.getAttribute('data-href'),
        link.getAttribute('href'),
        link.getAttribute('aria-label'),
      ].filter(Boolean);

      let path = null;
      let icon = '';
      for (const raw of rawCandidates) {
        const resolved = this.resolveLinkToPath(raw, sourcePath);
        if (!resolved) continue;
        path = resolved;
        icon = this.getIconForFilePath(resolved) || this.getIconForFolderPath(resolved);
        if (icon) break;
      }

      if (!path) {
        if (iconSpan) iconSpan.remove();
        return;
      }

      if (!iconSpan) {
        iconSpan = this.createIconSpan(icon, 'npis-link-icon');
        link.insertBefore(iconSpan, link.firstChild);
      }
      this.updateSpecialFallbackClass(iconSpan, path, icon);
      this.setIconContent(iconSpan, icon);
    });
  }

  resolveLinkToPath(href, sourcePath = '') {
    try {
      let clean = href;
      if (clean.startsWith('#')) return null;
      clean = decodeURIComponent(clean);
      const hashIndex = clean.indexOf('#');
      if (hashIndex !== -1) clean = clean.slice(0, hashIndex);
      const pipeIndex = clean.indexOf('|');
      if (pipeIndex !== -1) clean = clean.slice(0, pipeIndex);
      if (!clean) return null;

      const directMd = this.app.vault.getAbstractFileByPath(clean + '.md');
      if (directMd && directMd.path) return directMd.path;

      const resolved = this.app.metadataCache.getFirstLinkpathDest(clean, sourcePath || this.app.workspace.getActiveFile()?.path || '');
      if (resolved?.path) return resolved.path;

      const direct = this.app.vault.getAbstractFileByPath(clean);
      if (direct && direct.path) return direct.path;
      return null;
    } catch {
      return null;
    }
  }

  attachIconPickerClick(el, file) {
    if (!el || !file) return;
    el._npisTargetFile = file;
    if (el._npisClickBound) return;
    el._npisClickBound = true;
    const stop = (evt) => {
      evt.preventDefault();
      evt.stopPropagation();
    };
    el.addEventListener('mousedown', stop);
    el.addEventListener('pointerdown', stop);
    el.addEventListener('click', async (evt) => {
      evt.preventDefault();
      evt.stopPropagation();
      const targetFile = el._npisTargetFile || file;
      this.openIconMenu(targetFile);
    });
    el.style.cursor = 'pointer';
    el.title = 'Choisir une icône';
  }

  openIconMenu(file) {
    const current = this.fileIconCache.get(file.path) || '';
    const modal = new OfflineIconPickerModal(this.app, current, async (value) => {
      if (value === null) return this.clearFileIcon(file);
      const trimmed = String(value).trim();
      if (!trimmed) return this.clearFileIcon(file);
      await this.setFileIcon(file, trimmed);
    });
    modal.open();
  }

  async setFileIcon(file, icon) {
    try {
      await this.app.fileManager.processFrontMatter(file, (fm) => {
        if (!fm || typeof fm !== 'object') return;
        fm[this.settings.iconField] = icon;
      });
      this.refreshCaches();
      this.refreshAll();
      window.setTimeout(() => {
        this.refreshCaches();
        this.refreshAll();
      }, 120);
    } catch (e) {
      new Notice('Impossible de définir l’icône');
      console.error(e);
    }
  }

  async clearFileIcon(file) {
    try {
      await this.app.fileManager.processFrontMatter(file, (fm) => {
        if (fm && Object.prototype.hasOwnProperty.call(fm, this.settings.iconField)) {
          delete fm[this.settings.iconField];
        }
      });
      this.refreshCaches();
      this.refreshAll();
      window.setTimeout(() => {
        this.refreshCaches();
        this.refreshAll();
      }, 120);
    } catch (e) {
      new Notice('Impossible de retirer l’icône');
      console.error(e);
    }
  }
};
